var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 11월 9일 런던, 화이트 채플\\n<color=#ffd34c>심야</color>","JPN":"1888年11月9日　ロンドン、ホワイトチャペル\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年11月9日 倫敦，白教堂<color=#ffd34c>深夜</color>","SCN":"1888年11月9日 伦敦，白教堂<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"저는 이 세상이 변하길 바라거든요.","JPN":"私はこの世界が変わってほしいんです。","ENG":"Because I wish the world would change.","TWN":"我希望這個世界能夠改變。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 필요하답니다. 이 세계에 천사를 강림시키기 위한 제물이.","JPN":"だから必要なんです。この世界に天使を降臨させるための生贄が。","ENG":"That's why it's necessary. To give offerings so that an angel will descend to this world.","TWN":"所以為了讓天使降臨到這個世界，祭品是必要的——"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"당신의 가슴에 새겨진 증오스러운 <color=#ffd34c>증표</color>로써.","JPN":"あなたの胸に刻まれている憎い<color=#ffd34c>印</color>をもって。","ENG":"With that repulsive <color=#ffd34c>mark</color> that's on your chest.","TWN":"不如把銘刻在你胸前的那個憎惡<color=#ffd34c>印記</color>給我吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANGELINA_SWANSONG_NPC_NULL","text":{"KOREA":"……뭐?","JPN":"……えっ？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"ANGELINA_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이건, 파노라마의 거울 조각……?","JPN":"これは、パノラマの鏡の破片……？","ENG":"That's a Panorama mirror fragment...?","TWN":"這是，全景的碎片……？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다는, 말은 설마……?","JPN":"ということは、まさか……？","ENG":"Then, that means...?","TWN":"難道你是……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"믿고 싶지 않았어.","JPN":"信じたくなかった。","ENG":"I didn't want to believe it.","TWN":"我還是不想相信。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 믿지 않았기 때문에 이 역할을 수락한 건데…….","JPN":"いいえ、信じたくなかったからこそ、この役を引き受けたのに……","ENG":"No, it's because I didn't believe it that I accepted this role...","TWN":"不，就是因為我不敢相信，所以才接受了這個角色……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말로 너였구나. 메리 제인.","JPN":"本当にあなただったのね、メリー・ジェーン。","ENG":"So, it was really you, Mary Jane.","TWN":"真的是你啊，瑪麗·珍。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 이젠 심야의 살인마라고 불러야 할까?","JPN":"いや、もう深夜の殺人鬼と呼ぶべきかな？","ENG":"Or rather, should I call you the Midnight Killer?","TWN":"不，是不是該改叫你午夜殺人魔了？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"스완 클레어……?","JPN":"スワン・クレア……？","ENG":"Swan Claire...?","TWN":"史旺·克萊爾……？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇네. 네가 여기 있다는 건, 모든 게 정해진 <color=#ffd34c>각본</color>이라는 거겠지.","JPN":"そうね。あなたがここにいるってことは、すべてが決められた<color=#ffd34c>脚本</color>だったってことなのよね。","ENG":"Yes. And the reason you are here means that everything is according to the <color=#ffd34c>script</color>.","TWN":"沒錯。你在這裡，表示一切都是按照<color=#ffd34c>劇本</color>進行的吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"실수였어. 역시 그날 모리어티의 계획대로, 극장에서 널 죽였어야 했는데.","JPN":"失敗したわ。やっぱりあの日、モリアーティの計画通り、劇場であなたを殺すべきだったのよ。","ENG":"It was a mistake. I should have killed you at the theater that day, just as Moriarty planned.","TWN":"是我的失誤。果然那天應該按照莫里蒂的計畫，在劇院殺了你。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"극장이라고……?","JPN":"劇場……？","ENG":"The theater...?","TWN":"劇院……嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"후후, 상관없다니 그거 섭섭한 소리네.","JPN":"ふふ、関係ないだなんて悲しいこと言うね。","ENG":"Haha, you're upsetting me by saying that this has nothing to do with me.","TWN":"呵呵，你說無所謂，那可真讓人傷心啊。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"나는 네 전속 스태프이고, 너는 우리 극단을 대표하는 프리마돈나인걸?","JPN":"私はあなたの専属スタッフで、あなたは我が劇団を代表するプリマドンナなのよ？","ENG":"I'm your personal staff, and you're the prima donna that represents our theater.","TWN":"我是你的專屬助理，而你是我們劇團的首席女主角喔？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐……?","JPN":"えっ……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"속였다고 해도 상관없어. 기만이라고 해도 괜찮아.","JPN":"騙されたとしても構わない。欺かれたとしても大丈夫。","ENG":"Call it deceiving or fraud, I don't really care.","TWN":"就算被騙了也沒關係，就算是利用也沒關係……"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"왜냐하면 무대 위에서 너는 정말로 아름답게 빛났으니까.","JPN":"だって、舞台の上のあなたは本当に美しく輝いていたから。","ENG":"Because you were always shining so brilliantly up on stage.","TWN":"因為在舞台上的你，真的非常閃耀、非常美麗。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"MARY_SWANSONG_NPC_SWAN","text":{"KOREA":"그래, 마치 백조처럼.","JPN":"だって、舞台の上のあなたは本当に美しく輝いていたから。","ENG":"Yes, you were literally a swan.","TWN":"是的，就像天鵝一樣。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"MARY_SWANSONG_NPC_SWAN","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};